3	import React, { useEffect, useRef, useState, useMemo, useCallback, type ReactNode } from "react";
4	import type { ClientMessage, ServerMessage, SessionPatch } from "@/lib/mux-protocol";
5	
6	export type TerminalLifecycleEvent =
7	  | { type: "opened" }
8	  | { type: "exited"; code: number }
9	  | { type: "error"; message: string };
10	
11	interface MuxContextValue {
12	  subscribeTerminal: (id: string, callback: (data: string) => void) => () => void;
13	  subscribeTerminalLifecycle: (id: string, callback: (event: TerminalLifecycleEvent) => void) => () => void;
14	  writeTerminal: (id: string, data: string) => void;
15	  openTerminal: (id: string) => void;
16	  closeTerminal: (id: string) => void;
17	  resizeTerminal: (id: string, cols: number, rows: number) => void;
18	  status: "connecting" | "connected" | "reconnecting" | "disconnected";
19	  sessions: SessionPatch[];
20	}
21	
22	const MuxContext = React.createContext<MuxContextValue | undefined>(undefined);
23	
24	export function useMux(): MuxContextValue {
25	  const context = React.useContext(MuxContext);
26	  if (!context) {
27	    throw new Error("useMux() must be used within <MuxProvider>");
28	  }
29	  return context;
30	}
31	
32	/** Like useMux() but returns undefined when outside a MuxProvider (safe for tests). */
33	export function useMuxOptional(): MuxContextValue | undefined {
34	  return React.useContext(MuxContext);
35	}
36	
37	interface RuntimeTerminalConfig {
38	  directTerminalPort?: unknown;
39	  proxyWsPath?: unknown;
40	}
41	
42	function normalizePortValue(value: unknown): string | undefined {
43	  if (typeof value !== "string" && typeof value !== "number") return undefined;
44	  const parsed = Number.parseInt(String(value), 10);
45	  if (!Number.isInteger(parsed) || parsed <= 0 || parsed > 65535) return undefined;
46	  return String(parsed);
47	}
48	
49	function normalizePathValue(value: unknown): string | undefined {
50	  if (typeof value !== "string") return undefined;
51	  const trimmed = value.trim();
52	  if (!trimmed.startsWith("/")) return undefined;
53	  return trimmed;
54	}
55	
56	function buildMuxWsUrl(runtimeConfig: { directTerminalPort?: string; proxyWsPath?: string }): string {
57	  const loc = window.location;
58	  const protocol = loc.protocol === "https:" ? "wss:" : "ws:";
59	
60	  // Runtime proxy path takes priority (set by `ao start` via TERMINAL_WS_PATH env var)
61	  const proxyWsPath = runtimeConfig.proxyWsPath ?? process.env.NEXT_PUBLIC_TERMINAL_WS_PATH;
62	  if (proxyWsPath) {
63	    const basePath = proxyWsPath.replace(/\/ws\/?$/, "");
64	    return `${protocol}//${loc.host}${basePath}/mux`;
65	  }
66	
67	  // Port-less or standard ports: use path-based routing (reverse proxy expected)
68	  if (loc.port === "" || loc.port === "443" || loc.port === "80") {
69	    return `${protocol}//${loc.hostname}/ao-terminal-mux`;
70	  }
71	
72	  // Direct port connection — prefer runtime-configured port, fall back to env/default
73	  const port = runtimeConfig.directTerminalPort ?? process.env.NEXT_PUBLIC_DIRECT_TERMINAL_PORT ?? "14801";
74	  return `${protocol}//${loc.hostname}:${port}/mux`;
75	}
76	
77	export function MuxProvider({ children }: { children: ReactNode }) {
78	  const wsRef = useRef<WebSocket | null>(null);
79	  const subscribersRef = useRef(new Map<string, Set<(data: string) => void>>());
80	  const lifecycleSubscribersRef = useRef(new Map<string, Set<(event: TerminalLifecycleEvent) => void>>());
81	  const openedTerminalsRef = useRef(new Set<string>());
82	  const [status, setStatus] = useState<"connecting" | "connected" | "reconnecting" | "disconnected">(
83	    "connecting",
84	  );
85	  const [sessions, setSessions] = useState<SessionPatch[]>([]);
86	  const reconnectAttempt = useRef(0);
87	  const reconnectTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
88	  const runtimeConfigRef = useRef<{ directTerminalPort?: string; proxyWsPath?: string }>({});
89	  const isDestroyedRef = useRef(false);
90	
91	  const connect = useCallback(() => {
92	    if (wsRef.current) {
93	      return;
94	    }
95	
96	    setStatus("connecting");
97	
98	    try {
99	      const url = buildMuxWsUrl(runtimeConfigRef.current);
100	      console.log("[MuxProvider] Connecting to", url);
101	      const ws = new WebSocket(url);
102	      // Assign immediately so cleanup can close it even during CONNECTING state
103	      wsRef.current = ws;
104	
105	      ws.addEventListener("open", () => {
106	        if (isDestroyedRef.current) {
107	          ws.close();
108	          return;
109	        }
110	        console.log("[MuxProvider] Connected");
111	        setStatus("connected");
112	        reconnectAttempt.current = 0;
113	
114	        // Re-open previously opened terminals
115	        for (const terminalId of openedTerminalsRef.current) {
116	          const openMsg: ClientMessage = {
117	            ch: "terminal",
118	            id: terminalId,
119	            type: "open",
120	          };
121	          ws.send(JSON.stringify(openMsg));
122	        }
123	
124	        // Always subscribe to sessions
125	        const subMsg: ClientMessage = {
126	          ch: "subscribe",
127	          topics: ["sessions"],
128	        };
129	        ws.send(JSON.stringify(subMsg));
130	      });
131	
132	      ws.addEventListener("message", (event) => {
133	        try {
134	          const msg = JSON.parse(event.data as string) as ServerMessage;
135	
136	          const notifyTerminalLifecycle = (id: string, lifecycleEvent: TerminalLifecycleEvent) => {
137	            const lifecycleSubscribers = lifecycleSubscribersRef.current.get(id);
138	            if (!lifecycleSubscribers) return;
139	            for (const callback of lifecycleSubscribers) {
140	              callback(lifecycleEvent);
141	            }
142	          };
143	
144	          if (msg.ch === "terminal") {
145	            if (msg.type === "data") {
146	              // Push to subscribers
147	              const subs = subscribersRef.current.get(msg.id);
148	              if (subs) {
149	                for (const callback of subs) {
150	                  callback(msg.data);
151	                }
152	              }
153	            } else if (msg.type === "opened") {
154	              // Terminal opened successfully
155	              openedTerminalsRef.current.add(msg.id);
156	              notifyTerminalLifecycle(msg.id, { type: "opened" });
157	            } else if (msg.type === "exited") {
158	              // PTY exited and could not be re-attached — remove so it isn't
159	              // re-opened on reconnect, and surface a terminal-level error chunk
160	              openedTerminalsRef.current.delete(msg.id);
161	              notifyTerminalLifecycle(msg.id, { type: "exited", code: msg.code });
162	              const subs = subscribersRef.current.get(msg.id);
163	              if (subs) {
164	                const notice = `\r\n\x1b[31m[Terminal exited with code ${msg.code}]\x1b[0m\r\n`;
165	                for (const callback of subs) {
166	                  callback(notice);
167	                }
168	              }
169	            } else if (msg.type === "error") {
